    51→/*
    52→ * Implement DNS resolution interface using libudns
    53→ */
    54→
    55→struct ResolvQuery {
    56→    void (*client_cb)(struct sockaddr *, void *);
    57→    void (*client_free_cb)(void *);
    58→    void *client_cb_data;
    59→    struct dns_query *queries[2];
    60→    size_t response_count;
    61→    struct sockaddr **responses;
    62→    uint16_t port;
    63→};
    64→
    65→extern int verbose;
    66→
    67→static struct ev_io resolv_io_watcher;
    68→static struct ev_timer resolv_timeout_watcher;
    69→static const int MODE_IPV4_ONLY  = 0;
    70→static const int MODE_IPV6_ONLY  = 1;
    71→static const int MODE_IPV4_FIRST = 2;
    72→static const int MODE_IPV6_FIRST = 3;
    73→static int resolv_mode           = 0;
    74→
    75→static void resolv_sock_cb(struct ev_loop *, struct ev_io *, int);
    76→static void resolv_timeout_cb(struct ev_loop *, struct ev_timer *, int);
    77→static void dns_query_v4_cb(struct dns_ctx *, struct dns_rr_a4 *, void *);
    78→static void dns_query_v6_cb(struct dns_ctx *, struct dns_rr_a6 *, void *);
    79→static void dns_timer_setup_cb(struct dns_ctx *, int, void *);
    80→static void process_client_callback(struct ResolvQuery *);
    81→static inline int all_queries_are_null(struct ResolvQuery *);
    82→static struct sockaddr *choose_ipv4_first(struct ResolvQuery *);
    83→static struct sockaddr *choose_ipv6_first(struct ResolvQuery *);
    84→static struct sockaddr *choose_any(struct ResolvQuery *);
    85→
    86→int
    87→resolv_init(struct ev_loop *loop, char **nameservers, int nameserver_num, int ipv6first)
    88→{
    89→    if (ipv6first)
    90→        resolv_mode = MODE_IPV6_FIRST;
    91→    else
    92→        resolv_mode = MODE_IPV4_FIRST;
    93→
    94→    struct dns_ctx *ctx = &dns_defctx;
    95→    if (nameservers == NULL) {
    96→        /* Nameservers not specified, use system resolver config */
    97→        dns_init(ctx, 0);
    98→    } else {
    99→        dns_reset(ctx);
   100→
   101→        for (int i = 0; i < nameserver_num; i++) {
   102→            char *server = nameservers[i];
   103→            dns_add_serv(ctx, server);
   104→        }
   105→    }
   106→
   107→    int sockfd = dns_open(ctx);
   108→    if (sockfd < 0) {
   109→        FATAL("Failed to open DNS resolver socket");
   110→    }
   111→
   112→    if (nameserver_num == 1 && nameservers != NULL) {
   113→        if (strncmp("127.0.0.1", nameservers[0], 9) == 0
   114→            || strncmp("::1", nameservers[0], 3) == 0) {
   115→            if (verbose) {
   116→                LOGI("bind UDP resolver to %s", nameservers[0]);
   117→            }
   118→            if (bind_to_address(sockfd, nameservers[0]) == -1)
   119→                ERROR("bind_to_address");
   120→        }
   121→    }
   122→
   123→#ifdef __MINGW32__
   124→    setnonblocking(sockfd);
   125→#else
   126→    int flags = fcntl(sockfd, F_GETFL, 0);
   127→    fcntl(sockfd, F_SETFL, flags | O_NONBLOCK);
   128→#endif
   129→
   130→    ev_io_init(&resolv_io_watcher, resolv_sock_cb, sockfd, EV_READ);
   131→    resolv_io_watcher.data = ctx;
   132→
   133→    ev_io_start(loop, &resolv_io_watcher);
   134→
   135→    ev_timer_init(&resolv_timeout_watcher, resolv_timeout_cb, 0.0, 0.0);
   136→    resolv_timeout_watcher.data = ctx;
   137→
   138→    dns_set_tmcbck(ctx, dns_timer_setup_cb, loop);
   139→
   140→    return sockfd;
   141→}
   142→
   143→void
   144→resolv_shutdown(struct ev_loop *loop)
   145→{
   146→    struct dns_ctx *ctx = (struct dns_ctx *)resolv_io_watcher.data;
   147→
   148→    ev_io_stop(loop, &resolv_io_watcher);
   149→
   150→    if (ev_is_active(&resolv_timeout_watcher)) {
   151→        ev_timer_stop(loop, &resolv_timeout_watcher);
   152→    }
   153→
   154→    dns_close(ctx);
   155→}
   156→
   157→struct ResolvQuery *
   158→resolv_query(const char *hostname, void (*client_cb)(struct sockaddr *, void *),
   159→             void (*client_free_cb)(void *), void *client_cb_data,
   160→             uint16_t port)
   161→{
   162→    struct dns_ctx *ctx = (struct dns_ctx *)resolv_io_watcher.data;
   163→
   164→    /*
   165→     * Wrap udns's call back in our own
   166→     */
   167→    struct ResolvQuery *cb_data = ss_malloc(sizeof(struct ResolvQuery));
   168→    if (cb_data == NULL) {
   169→        LOGE("Failed to allocate memory for DNS query callback data.");
   170→        return NULL;
   171→    }
   172→    memset(cb_data, 0, sizeof(struct ResolvQuery));
   173→
   174→    cb_data->client_cb      = client_cb;
   175→    cb_data->client_free_cb = client_free_cb;
   176→    cb_data->client_cb_data = client_cb_data;
   177→    memset(cb_data->queries, 0, sizeof(cb_data->queries));
   178→    cb_data->response_count = 0;
   179→    cb_data->responses      = NULL;
   180→    cb_data->port           = port;
   181→
   182→    /* Submit A and AAAA queries */
   183→    if (resolv_mode != MODE_IPV6_ONLY) {
   184→        cb_data->queries[0] = dns_submit_a4(ctx,
   185→                                            hostname, 0,
   186→                                            dns_query_v4_cb, cb_data);
   187→        if (cb_data->queries[0] == NULL) {
   188→            LOGE("Failed to submit DNS query: %s",
   189→                 dns_strerror(dns_status(ctx)));
   190→        }
   191→    }
   192→
   193→    if (resolv_mode != MODE_IPV4_ONLY) {
   194→        cb_data->queries[1] = dns_submit_a6(ctx,
   195→                                            hostname, 0,
   196→                                            dns_query_v6_cb, cb_data);
   197→        if (cb_data->queries[1] == NULL) {
   198→            LOGE("Failed to submit DNS query: %s",
   199→                 dns_strerror(dns_status(ctx)));
   200→        }
   201→    }
   202→
   203→    if (all_queries_are_null(cb_data)) {
   204→        if (cb_data->client_free_cb != NULL) {
   205→            cb_data->client_free_cb(cb_data->client_cb_data);
   206→        }
   207→        ss_free(cb_data);
   208→    }
   209→
   210→    return cb_data;
   211→}
   212→
   213→void
   214→resolv_cancel(struct ResolvQuery *query_handle)
   215→{
   216→    struct ResolvQuery *cb_data = (struct ResolvQuery *)query_handle;
   217→    struct dns_ctx *ctx         = (struct dns_ctx *)resolv_io_watcher.data;
   218→
   219→    for (int i = 0; i < sizeof(cb_data->queries) / sizeof(cb_data->queries[0]);
   220→         i++)
   221→        if (cb_data->queries[i] != NULL) {
   222→            dns_cancel(ctx, cb_data->queries[i]);
   223→            ss_free(cb_data->queries[i]);
   224→        }
   225→
   226→    if (cb_data->client_free_cb != NULL) {
   227→        cb_data->client_free_cb(cb_data->client_cb_data);
   228→    }
   229→
   230→    ss_free(cb_data);
   231→}
   232→
   233→/*
   234→ * DNS UDP socket activity callback
   235→ */
   236→static void
   237→resolv_sock_cb(struct ev_loop *loop, struct ev_io *w, int revents)
   238→{
   239→    struct dns_ctx *ctx = (struct dns_ctx *)w->data;
   240→
   241→    if (revents & EV_READ) {
   242→        dns_ioevent(ctx, ev_now(loop));
   243→    }
   244→}
   245→
   246→/*
   247→ * Wrapper for client callback we provide to udns
   248→ */
   249→static void
   250→dns_query_v4_cb(struct dns_ctx *ctx, struct dns_rr_a4 *result, void *data)
   251→{
   252→    struct ResolvQuery *cb_data = (struct ResolvQuery *)data;
   253→
   254→    if (result == NULL) {
   255→        if (verbose) {
   256→            LOGI("IPv4 resolv: %s", dns_strerror(dns_status(ctx)));
   257→        }
   258→    } else if (result->dnsa4_nrr > 0) {
   259→        struct sockaddr **new_responses = ss_realloc(cb_data->responses,
   260→                                                     (cb_data->response_count +
   261→                                                      result->dnsa4_nrr) *
   262→                                                     sizeof(struct sockaddr *));
   263→        if (new_responses == NULL) {
   264→            LOGE("Failed to allocate memory for additional DNS responses");
   265→        } else {
   266→            cb_data->responses = new_responses;
   267→
   268→            for (int i = 0; i < result->dnsa4_nrr; i++) {
   269→                struct sockaddr_in *sa = ss_malloc(sizeof(struct sockaddr_in));
   270→                memset(sa, 0, sizeof(struct sockaddr_in));
   271→                sa->sin_family = AF_INET;
   272→                sa->sin_port   = cb_data->port;
   273→                sa->sin_addr   = result->dnsa4_addr[i];
   274→
   275→                cb_data->responses[cb_data->response_count] =
   276→                    (struct sockaddr *)sa;
   277→                if (cb_data->responses[cb_data->response_count] == NULL) {
   278→                    LOGE(
   279→                        "Failed to allocate memory for DNS query result address");
   280→                } else {
   281→                    cb_data->response_count++;
   282→                }
   283→            }
   284→        }
   285→    }
   286→
   287→    ss_free(result);
   288→    cb_data->queries[0] = NULL; /* mark A query as being completed */
   289→
   290→    /* Once all queries have completed, call client callback */
   291→    if (all_queries_are_null(cb_data)) {
   292→        return process_client_callback(cb_data);
   293→    }
   294→}
   295→
   296→static void
   297→dns_query_v6_cb(struct dns_ctx *ctx, struct dns_rr_a6 *result, void *data)
   298→{
   299→    struct ResolvQuery *cb_data = (struct ResolvQuery *)data;
   300→
   301→    if (result == NULL) {
   302→        if (verbose) {
   303→            LOGI("IPv6 resolv: %s", dns_strerror(dns_status(ctx)));
   304→        }
   305→    } else if (result->dnsa6_nrr > 0) {
   306→        struct sockaddr **new_responses = ss_realloc(cb_data->responses,
   307→                                                     (cb_data->response_count +
   308→                                                      result->dnsa6_nrr) *
   309→                                                     sizeof(struct sockaddr *));
   310→        if (new_responses == NULL) {
   311→            LOGE("Failed to allocate memory for additional DNS responses");
   312→        } else {
   313→            cb_data->responses = new_responses;
   314→
   315→            for (int i = 0; i < result->dnsa6_nrr; i++) {
   316→                struct sockaddr_in6 *sa = ss_malloc(sizeof(struct sockaddr_in6));
   317→                memset(sa, 0, sizeof(struct sockaddr_in6));
   318→                sa->sin6_family = AF_INET6;
   319→                sa->sin6_port   = cb_data->port;
   320→                sa->sin6_addr   = result->dnsa6_addr[i];
   321→
   322→                cb_data->responses[cb_data->response_count] =
   323→                    (struct sockaddr *)sa;
   324→                if (cb_data->responses[cb_data->response_count] == NULL) {
   325→                    LOGE(
   326→                        "Failed to allocate memory for DNS query result address");
   327→                } else {
   328→                    cb_data->response_count++;
   329→                }
   330→            }
   331→        }
   332→    }
   333→
   334→    ss_free(result);
   335→    cb_data->queries[1] = NULL; /* mark AAAA query as being completed */
   336→
   337→    /* Once all queries have completed, call client callback */
   338→    if (all_queries_are_null(cb_data)) {
   339→        return process_client_callback(cb_data);
   340→    }
   341→}
   342→
   343→/*
   344→ * Called once all queries have been completed
   345→ */
   346→static void
   347→process_client_callback(struct ResolvQuery *cb_data)
   348→{
   349→    struct sockaddr *best_address = NULL;
   350→
   351→    if (resolv_mode == MODE_IPV4_FIRST) {
   352→        best_address = choose_ipv4_first(cb_data);
   353→    } else if (resolv_mode == MODE_IPV6_FIRST) {
   354→        best_address = choose_ipv6_first(cb_data);
   355→    } else {
   356→        best_address = choose_any(cb_data);
   357→    }
   358→
   359→    cb_data->client_cb(best_address, cb_data->client_cb_data);
   360→
   361→    for (int i = 0; i < cb_data->response_count; i++)
   362→        ss_free(cb_data->responses[i]);
   363→
   364→    ss_free(cb_data->responses);
   365→    if (cb_data->client_free_cb != NULL) {
   366→        cb_data->client_free_cb(cb_data->client_cb_data);
   367→    }
   368→    ss_free(cb_data);
   369→}
   370→
   371→static struct sockaddr *
   372→choose_ipv4_first(struct ResolvQuery *cb_data)
   373→{
   374→    for (int i = 0; i < cb_data->response_count; i++)
   375→        if (cb_data->responses[i]->sa_family == AF_INET) {
   376→            return cb_data->responses[i];
   377→        }
   378→
   379→    return choose_any(cb_data);
   380→}
   381→
   382→static struct sockaddr *
   383→choose_ipv6_first(struct ResolvQuery *cb_data)
   384→{
   385→    for (int i = 0; i < cb_data->response_count; i++)
   386→        if (cb_data->responses[i]->sa_family == AF_INET6) {
   387→            return cb_data->responses[i];
   388→        }
   389→
   390→    return choose_any(cb_data);
   391→}
   392→
   393→static struct sockaddr *
   394→choose_any(struct ResolvQuery *cb_data)
   395→{
   396→    if (cb_data->response_count >= 1) {
   397→        return cb_data->responses[0];
   398→    }
   399→
   400→    return NULL;
   401→}
   402→
   403→/*
   404→ * DNS timeout callback
   405→ */
   406→static void
   407→resolv_timeout_cb(struct ev_loop *loop, struct ev_timer *w, int revents)
   408→{
   409→    struct dns_ctx *ctx = (struct dns_ctx *)w->data;
   410→
   411→    if (revents & EV_TIMER) {
   412→        dns_timeouts(ctx, 30, ev_now(loop));
   413→    }
   414→}
   415→
   416→/*
   417→ * Callback to setup DNS timeout callback
   418→ */
   419→static void
   420→dns_timer_setup_cb(struct dns_ctx *ctx, int timeout, void *data)
   421→{
   422→    struct ev_loop *loop = (struct ev_loop *)data;
   423→
   424→    if (ev_is_active(&resolv_timeout_watcher)) {
   425→        ev_timer_stop(loop, &resolv_timeout_watcher);
   426→    }
   427→
   428→    if (ctx != NULL && timeout >= 0) {
   429→        ev_timer_set(&resolv_timeout_watcher, timeout, 0.0);
   430→        ev_timer_start(loop, &resolv_timeout_watcher);
   431→    }
   432→}
   433→
   434→static inline int
   435→all_queries_are_null(struct ResolvQuery *cb_data)
   436→{
   437→    int result = 1;
   438→
   439→    for (int i = 0; i < sizeof(cb_data->queries) / sizeof(cb_data->queries[0]);
   440→         i++)
   441→        result = result && cb_data->queries[i] == NULL;
   442→
   443→    return result;
   444→}
